const msg = ($input.first().json.user_message || '').toLowerCase().trim();

// Sinais inequivocos de despedida — sempre encerram
const sinais_inequivocos = ['tchau','xau','flw','ate mais','adeus','👋','bye'];
// Sinais ambiguos — so encerram se todos os 4 dados ja foram coletados
const sinais_ambiguos = ['valeu','obrigado','👍','ok','oks','tudo bem','tmj','certo','entendi'];

const encerrando_inequivoco = sinais_inequivocos.some(s => msg.includes(s));
const encerrando_ambiguo    = !encerrando_inequivoco && sinais_ambiguos.some(
  s => msg === s || msg.startsWith(s + ' ') || msg.endsWith(' ' + s) || msg.includes(' ' + s + ' ')
);

return [{
  json: {
    ...$input.first().json,
    encerrando_inequivoco,
    encerrando_ambiguo
  }
}];

const estadoAtual = $('Monta Prompts').first().json.estado_atual;
const rawOutput   = $('Extractor').first().json.text || '';

let extraido = {};
try {
  const clean = rawOutput.replace(/```json|```/g, '').trim();
  extraido = JSON.parse(clean);
} catch(e) {
  extraido = {};
}

const nps = (extraido.nps !== null && extraido.nps !== undefined)
  ? extraido.nps
  : estadoAtual.nps;

const sugestao = (extraido.sugestao !== null && extraido.sugestao !== undefined && extraido.sugestao !== '')
  ? extraido.sugestao
  : estadoAtual.sugestao;

const objecoes = (extraido.objecoes !== null && extraido.objecoes !== undefined && extraido.objecoes !== '')
  ? extraido.objecoes
  : estadoAtual.objecoes;

// intent_matricula: true sempre prevalece sobre false (correcao de erro de extracao)
const intent_matricula = extraido.intent_matricula === true
  ? true
  : (extraido.intent_matricula === false && estadoAtual.intent_matricula !== true)
  ? false
  : estadoAtual.intent_matricula;

const encerrando    = $('Monta Prompts').first().json.encerrando || false;
const faltando      = $('Monta Prompts').first().json.faltando || [];
const todos_coletados = encerrando || (
  nps !== null &&
  sugestao !== null &&
  objecoes !== null &&
  intent_matricula !== null
);

const session_id = $('Monta Prompts').first().json.session_id;

return [{
  json: {
    session_id,
    nps,
    sugestao,
    objecoes,
    intent_matricula,
    todos_coletados
  }
}];
